span class=&#34;string&#34;&gt;&amp;#x27;0&amp;#x27;&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;COMMENT&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;最大变更历史数量&amp;#x27;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;string&#34;&gt;`gmt_create`&lt;/span&gt; datetime &lt;span class=&#34;keyword&#34;&gt;NOT&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;DEFAULT&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;2010-05-05 00:00:00&amp;#x27;&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;COMMENT&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;创建时间&amp;#x27;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;string&#34;&gt;`gmt_modified`&lt;/span&gt; datetime &lt;span class=&#34;keyword&#34;&gt;NOT&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;DEFAULT&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;2010-05-05 00:00:00&amp;#x27;&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;COMMENT&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;修改时间&amp;#x27;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  PRIMARY &lt;span class=&#34;keyword&#34;&gt;KEY&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;`id`&lt;/span&gt;),&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;UNIQUE&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;KEY&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;`uk_group_id`&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;`group_id`&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;) &lt;span class=&#34;keyword&#34;&gt;ENGINE&lt;/span&gt;=&lt;span class=&#34;keyword&#34;&gt;InnoDB&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;DEFAULT&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;CHARSET&lt;/span&gt;=utf8 &lt;span class=&#34;keywor